#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int mod=998244353,N=20000005;
ll len[N],mx,mid,t,n,k;
ll manacher(string ss)
{
	string s="  ";
	for(int i=0;i<ss.size();i++)
	{
		s+=ss[i];
		s+=" ";
	}
	n=s.size()-1;
	mx=mid=0;
	ll ans=0;
	for(int i=1;i<n;i++)
	{
		if(mx>i)
		{
			len[i]=min(len[2*mid-i],mx-i);
		}
		else len[i]=0;
		while(s[i+len[i]+1]==s[i-len[i]-1])
		{
			len[i]++;
		}
		if(i+len[i]>mx)
		{
			mx=i+len[i];
			mid=i;
		}
		ans=(ans+(len[i]+1)/2)%mod;
	}
	return ans;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>t;
	while(t--)
	{
		string s;
		cin>>n>>k>>s;
		ll t1=manacher(s);
		ll t2=manacher(s+s);
		ll t3=manacher(s+s+s);
		cout<<((t1+(t2-t1+mod)%mod*(k-1)%mod)%mod+(((k-1)*(k-2)/2%mod)*(((t3-2*t2+t1)%mod+mod)%mod)%mod))%mod<<"\n";
	}
	return 0;
}
